package org.jsoup.parser;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.jsoup.parser.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.jsoup.parser.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import static org.junit.Assert.*;

public class StepDefs {

    private String htmlInput;
    private String parsedOutput;

    @Given("the HTML input {string}")
    public void the_html_input(String html) {
        this.htmlInput = html;
    }

    @When("the HTML is parsed")
    public void the_html_is_parsed() {
        try {
            Document doc = Jsoup.parse(htmlInput);
            this.parsedOutput = doc.body().html();
        } catch (Exception e) {
            // Capture the exception for later verification
            this.parsedOutput = "Exception: " + e.getMessage();
        }
    }

    @Then("the parsed output should be {string}")
    public void the_parsed_output_should_be(String expected) {
        assertEquals("Parsed output should match expected result", expected, parsedOutput);
    }

    @Then("the parsing logic should treat {string} as a delimiter for the name")
    public void the_parsing_logic_should_treat_as_delimiter(String delimiter) {
        // This step is more about ensuring the parser handles the delimiter correctly
        // which will be verified through the actual parsing in the When step
        assertTrue("Parsing should handle the delimiter: " + delimiter, parsedOutput != null);
    }

    @Then("the result should be an empty {string} element followed by an empty {string} element")
    public void the_result_should_be_empty_elements(String element1, String element2) {
        String expectedPattern = element1 + "></" + element1 + "><" + element2 + "></" + element2 + ">";
        assertTrue("Result should contain empty elements in expected format", parsedOutput.contains(expectedPattern));
    }

    @Then("the {string} element should not have an attribute named {string}")
    public void the_element_should_not_have_attribute(String element, String attributeName) {
        // Check that the attribute doesn't exist in the form of attribute followed by the name
        assertFalse("Element should not have an attribute with the wrong name", parsedOutput.contains(attributeName));
    }
}

